window.__QUIZ_DATA__=[{"id":"theory>Agricultural Science Practical>2016>1>a","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"a","group":"","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"The diagram above illustrates an experimental setup to determine a soil property.    Study them carefully and answer the question that follows;    Suggest a suitable title for the experiment","images":["data:image/png;base64,"],"marking_scheme":"To compare porosity water holding/ retaining capacity of different soil types","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2016>1>b","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"b","group":"","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"The diagram above illustrates an experimental setup to determine a soil property.    Study them carefully and answer the question that follows;  Outline the procedure for carrying out the experiment","images":["data:image/png;base64,"],"marking_scheme":"Procedure for carrying out the experiment    Obtain samples of sandy, clayey and loamy so-Dry them under the sun.  Grind loamy and clayey soils  Plug the necks of three funnels with cotton wool  Put equal volumes of sandy, clayey and loamy soils separately into three funnels plugged with cotton wool.  Tap the funnels carefully on the bench until all air spaces are filled with soil  Stand each funnel in the open end of a measuring cylinder.  Pour 50cm of water into the funnel containing each soil sample.  Allow the setup to settle for at least 1 hour.  Measure the amount of water that dripped through each soil sample.  By subtracting the amount of water that dripped through each soil sample, obtain the amount of water retained in each soil sample.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2016>1>c","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"c","group":"","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"The diagram above illustrates an experimental setup to determine a soil property.    Study them carefully and answer the question that follows;  identify the soil samples in diagrams I, II, and III","images":["data:image/png;base64,"],"marking_scheme":"Set up I - Loam/Loamy soil  Set up II - Sand/Sandy soil  Set up III- Clay/Clayey soil","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2016>1>d","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"d","group":"","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"The diagram above illustrates an experimental setup to determine a soil property.    Study them carefully and answer the question that follows;  State two precautions to be taken when carrying out the experiment.","images":["data:image/png;base64,"],"marking_scheme":"Precautions to be taken when carrying out the experiment     Soil samples should be dried under the sun   Loam and clay should be ground before use  The funnels should be properly plugged with tton wool to prevent soil samples from dripping into the measuring cylinders,  The funnels should be properly tapped to close ces that could distort the experiment.  Cylinders should be placed on flat and level surface.  Water should be poured into the cylinder at the all same time.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2016>1>e>i","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"i","group":"","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"The diagram above illustrates an experimental setup to determine a soil property.    Study them carefully and answer the question that follows;  Which of the soil samples is prone to waterlogging?","images":["data:image/png;base64,"],"marking_scheme":"Soil sample in set up III (clay) is prone to waterlogging","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2016>1>e>ii","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"ii","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"The diagram above illustrates an experimental setup to determine a soil property.    Study them carefully and answer the question that follows;  Give one reason for your answer in (e)(i)","images":["data:image/png;base64,"],"marking_scheme":"Presence of small pore spaces which do not allow water to drain easily/small fine particles","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2016>2>a","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"a","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS","question":"Study specimens A (RANGING POLE), B (SURVEY PIN) and C (MEASURING TAPE) carefully and answer the following question.    Describe specimen A.","images":[],"marking_scheme":"Description of specimen A (Ranging pole);    Made of wood or light metal  Could be in various lengths  Usually circular or round  Painted in black, white, orange/red  Painted divisions are in a specific measurement  Has a pointed metal end","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2016>2>b","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"b","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS","question":"Study specimens A (RANGING POLE), B (SURVEY PIN) and C (MEASURING TAPE) carefully and answer the following question.  State two uses each of the specimens A, B and C.","images":[],"marking_scheme":"Uses of specimen A (Ranging pole);    For marking survey stations.  To measure off set/ short distance.  for marking straight lines over long distances.    Uses of specimen B (Survey pin);    To make chain length.  To make survey stations/ points.  Uses of specimen C (Measuring tape)    For taking measurements of length, breadth and height  For taking off sets. triangles.  For determining straight lines and right-angled","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2016>2>c","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"c","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : MAINTENANCE PRACTICES AND PRECAUTIONARY MEASURES","question":"Study specimens A (RANGING POLE), B (SURVEY PIN) and C (MEASURING TAPE) carefully and answer the following question.  State two ways of maintaining each of specimens A, B, and C","images":[],"marking_scheme":"Ways of maintaining specimens A, B and C    A (Ranging pole);    Oil the metal part after use to prevent rusting  Paint the bands when necessary  Sharpen the pointed end if blunt  Store in a cool dry place  B (Survey pin);    Sharpen the pointed end when blunt  Wipe with oil or grease after use when storing  Store in a cool dry place  Clean after use  C (Measuring tape);    Clean and dry after use/ wash and dry.  Roll back into the case after use.  Wipe steel tape with oil before storage.  Keep in a cool dry place.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2016>3>a>i","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"i","group":"","topic":"ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS","question":"Study specimens G (GRASSHOPPER), H (BEAN BEETLE), I (BIRD), and J (RAT) carefully and answer the following questions.    Classify specimens G and H according to their feeding habits.","images":[],"marking_scheme":"Classification of specimen G (Grasshopper) and H (Bean beetle) based on their feeding habits;    Specimen G (Grasshopper): biting and chewing insect pest  Specimen H (Bean beetle): boring insect pest","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2016>3>a>ii","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"ii","group":"","topic":"CROP PROTECTION : PESTS OF CROPS","question":"Study specimens G (GRASSHOPPER), H (BEAN BEETLE), I (BIRD), and J (RAT) carefully and answer the following questions.  Name one part of crops damaged by each of specimens G and H.","images":[],"marking_scheme":"Part of crops damaged by specimens G and H;    G (Grasshopper): Leaf, young shoot, succulent stem  H (Bean beetle): Seeds","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2016>3>a>iii","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"iii","group":"","topic":"CROP PROTECTION : PESTS OF CROPS","question":"Study specimens G (GRASSHOPPER), H (BEAN BEETLE), I (BIRD), and J (RAT) carefully and answer the following questions.  State three ways in which specimen H is economically important","images":[],"marking_scheme":"Ways in which specimen H (Bean beetle) is economically important    Destroys viability of seeds/destroys cotyledon.  Reduces market value of crop/quality of crop.  Increases farmer's cost of production.  Reduces the quantity of stored produce (seed)","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2016>3>b","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"b","group":"","topic":"CROP PROTECTION : PESTS OF CROPS","question":"Study specimens G (GRASSHOPPER), H (BEAN BEETLE), I (BIRD), and J (RAT) carefully and answer the following questions.  State four ways of controlling each of specimens I and J","images":[],"marking_scheme":"Ways of controlling Specimens I (Bird) J (Rat);    Specimen I (Bird);    Use of scarecrow/ bird scarer  Use of cage or string traps  Shooting with qun  Use of catapult  Drumming/noise making   Use of avicides/ poison  Specimen J (Rat);    Clean weeding of the farm  Trapping with baits  Use of rodenticides onno  Use of string or wire traps/ pit traps  Shooting with catapult  Smoking out of burrow/hole  Fencing Use of predators e.g. cat  Rat gum/mouse board","marks":"1","difficulty":"3"},{"id":"theory>Agricultural Science Practical>2016>4>a","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"a","group":"","topic":"ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS","question":"Study specimens N (BONE), O (EGG), P (ROUNDWORM) and Q (TICK) carefully and answer the following questions    Name three industries that use each of specimens N and O","images":[],"marking_scheme":"Industries that use specimens N (Bone) and o (Egg);    Specimen N (Bone)    Livestock/animal feed-mill  Interior decoration industry  Fertilizer industries  Adhesive making industry  Pharmaceutical industry- vaccines and hormones  Ceramic industry  Shoemaking industry  Specimen O (Egg);    Confectionery/food industry  Pharmaceutical industry  Cosmetic industry  Feed mill  Hatchery industry  Meat processing industry as anti-oxidant","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science Practical>2016>4>b","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"b","group":"","topic":"PARASITES","question":"Study specimens N (BONE), O (EGG), P (ROUNDWORM) and Q (TICK) carefully and answer the following questions  State five effects of specimen P on the host.","images":[],"marking_scheme":"Effects of specimen P (Roundworm) on the host    Internal haemorrhage/anaemia   Loss of weight/emaciation  Loss of appetite  Constipation/digestive problems in the body  Weakness  Reduction in livestock productivity  May cause death  Damage to the internal organ during migration of young ones","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2016>4>c","subject":"Agricultural Science Practical","year":"2016","type":"Practical","sub_label":"c","group":"","topic":"PARASITES","question":"Study specimens N (BONE), O (EGG), P (ROUNDWORM) and Q (TICK) carefully and answer the following questions  State four ways of controlling specimen Q on the farm.","images":[],"marking_scheme":"Ways of controlling specimen Q (Tick) on the farm    Dipping the animal in acaricide solution  Spraying the animal with acaricides  Rotational grazing/ paddocking  Burning of infested pasture  Quarantining new stock before being mixed with the existing stock  Good sanitation practices  Hand-picking and destroying the ticks  Use of predators e.g. cattle egret","marks":"1","difficulty":"2"}];